import { derived } from 'svelte/store';
import { gameStore } from '../gameStore';

// 直接使用 gameStore 的 grid 作为用户网格
export const userGrid = gameStore.grid;

// 直接使用 gameStore 的 invalidCells
export const invalidCells = gameStore.invalidCells;

// 导出其他 gameStore 状态
export const canUndo = gameStore.canUndo;
export const canRedo = gameStore.canRedo;
export const isComplete = gameStore.isComplete;
export const isExploring = gameStore.isExploring;
export const candidates = gameStore.candidates;
export const hint = gameStore.hint;

// 导出 gameStore 的方法
export function set(pos, value) {
  gameStore.guess(pos.y, pos.x, value);
}

export function applyHint(pos) {
  gameStore.useHint();
}

export function enterExploration() {
  gameStore.enterExploration();
}

export function exitExploration() {
  gameStore.exitExploration();
}

export function submitExploration() {
  gameStore.submitExploration();
}

export function getCandidates(row, col) {
  return gameStore.getCandidates(row, col);
}

export function getNextHint() {
  return gameStore.getNextHint();
}

export function isConflicted() {
  return gameStore.isConflicted();
}

export function isInExploration() {
  return gameStore.isInExploration();
}